16→    /// <summary>
17→    /// The program class containing the entry point of the application.
18→    /// </summary>
19→    public static class Program
20→    {
21→        /// <summary>
22→        /// The main method, entry point of the application.
23→        /// </summary>
24→        /// <param name="args">The program arguments.</param>
25→        /// <returns>A task that represents the asynchronous operation.</returns>
26→        public static Task Main(string[] args)
27→        {
28→            var builder = WebHost.CreateDefaultBuilder(args)
29→                .UseStartup<Startup>()
30→                .UseUrls($"http://*:{GetContainerPort()}")
31→                .UseShutdownTimeout(System.TimeSpan.FromMinutes(5));
32→
33→            builder.ConfigureLogging(logging =>
34→            {
35→                logging.ClearProviders();
36→                logging.AddConsole();
37→                logging.SetMinimumLevel(LogLevel.Information);
38→            });
39→
40→            builder.ConfigureServices(services =>
41→                services.AddHostedService<CodexUpdaterService>());
42→            var host = builder.Build();
43→            return host.RunAsync();
44→        }
45→
46→        /// <summary>
47→        /// Retrieves the container port from the environment variables.
48→        /// </summary>
49→        /// <returns>The container port as an integer. Defaults to 5004 if not set or invalid.</returns>
50→        private static int GetContainerPort()
51→        {
52→            const int DefaultPort = 5004;
53→            var port = System.Environment.GetEnvironmentVariable("HOSTING__PORT");
54→
55→            if (!string.IsNullOrEmpty(port) && int.TryParse(port, out int result))
56→            {
57→                return result;
58→            }
59→
60→            return DefaultPort;
61→        }
62→    }
63→}
